-- STEP 2: query [matrikkeleneiendomskartteig]
SELECT teigid, matrikkelnummertekst, kommunenummer, lagretberegnetareal AS area_m2, ST_AsGeoJSON(ST_Transform(omrade,4326)) AS geom_geojson FROM matrikkeleneiendomskartteig_36313fab8faa42d99cb779d86d1ca26d.teig WHERE kommunenummer = '3301' AND COALESCE(lagretberegnetareal, ST_Area(ST_Transform(omrade,25833))) > 5000 ORDER BY COALESCE(lagretberegnetareal, ST_Area(ST_Transform(omrade,25833))) DESC LIMIT 10;
